#!/usr/bin/env python3
"""
Demo script to showcase Black code formatter.
This file has intentionally poor formatting.
"""


def greet(name, greeting="Hello"):
    """Poorly formatted greeting function."""
    if name == "":
        return None
    message = greeting + ", " + name + "!"
    return message


class Person:
    def __init__(self, first_name, last_name, age=0):
        self.first_name = first_name
        self.last_name = last_name
        self.age = age

    def get_full_name(self):
        return self.first_name + " " + self.last_name

    def is_adult(self):
        return self.age >= 18


def main():
    people = [
        Person("John", "Doe", 25),
        Person("Jane", "Smith", 16),
        Person("Bob", "Johnson", 45),
    ]

    for person in people:
        print(greet(person.get_full_name()))
        if person.is_adult():
            print(f"{person.first_name} is an adult")
        else:
            print(f"{person.first_name} is a minor")


if __name__ == "__main__":
    main()

